        .clk        ( clk           ),
        .rst        ( device_reset  ),
        .in_valid   ( bar_rsp_valid ),
        .in_ctx     ( bar_rsp_ctx   ),
        .in_data    ( bar_rsp_data  ),
        .in_ready   ( bar_rsp_ready ),
        .out_valid  ( rd_rsp_valid  ),
        .out_ctx    ( rd_rsp_ctx    ),
        .out_data   ( rd_rsp_data   )
    );




    // NVMe register wires -- from bar_impl_device to admin responder
    wire [31:0] nvme_reg_cc;
    wire [31:0] nvme_reg_aqa;
    wire [31:0] nvme_reg_asq_lo;
    wire [31:0] nvme_reg_asq_hi;
    wire [31:0] nvme_reg_acq_lo;
    wire [31:0] nvme_reg_acq_hi;
    wire [31:0] nvme_reg_csts;



    pcileech_bar_impl_device #(
        .BAR_SIZE       ( 16384 )
    ) i_bar0(

        .rst            ( device_reset                  ),
        .clk            ( clk                           ),
        .wr_addr        ( wr_addr_bar0 ),
        .wr_be          ( wr_be                         ),
        .wr_data        ( wr_data                       ),
        .wr_valid       ( wr_valid && wr_bar[0] && bar0_wr_hit && !msix_wr_table_select && !msix_wr_pba_select ),
        .rd_req_ctx     ( rd_req_ctx                    ),
        .rd_req_addr    ( rd_req_addr_bar0 ),
        .rd_req_valid   ( rd_req_valid && rd_req_bar[0] && bar0_rd_hit && !msix_addr_hit ),

        .rd_rsp_ctx     ( bar0_raw_ctx                  ),
        .rd_rsp_data    ( bar0_raw_data                 ),
        .rd_rsp_valid   ( bar0_raw_valid                )

        ,
        .nvme_cc        ( nvme_reg_cc                   ),
        .nvme_aqa       ( nvme_reg_aqa                  ),
        .nvme_asq_lo    ( nvme_reg_asq_lo               ),
        .nvme_asq_hi    ( nvme_reg_asq_hi               ),
        .nvme_acq_lo    ( nvme_reg_acq_lo               ),
        .nvme_acq_hi    ( nvme_reg_acq_hi               ),
        .nvme_csts      ( nvme_reg_csts                 )

    );



    tlp_latency_emulator i_latency_emu(
        .clk            ( clk                           ),
        .rst            ( device_reset                  ),
        .crst_falling   ( hda_crst_falling              ),
        .req_valid      ( !bar0_buf_empty               ), // data available in buffer
        .req_ctx        ( bar0_buf_ctx_w                ), // read from buffer head
        .req_data       ( bar0_buf_data_w               ),
        .req_addr       ( bar0_buf_addr_w               ), // address from buffered request head
        .req_ready      (                               ),

        .rsp_valid      ( bar0_emu_valid                ),
        .rsp_ctx        ( bar0_emu_ctx                  ),
        .rsp_data       ( bar0_emu_data                 ),

        .rsp_ready      ( bar0_emu_ready ),
        .wr_valid       ( wr_valid && wr_bar[0] && bar0_wr_hit && !msix_wr_table_select && !msix_wr_pba_select ),
        .wr_addr        ( wr_addr_bar0 ),
        .wr_ack         ( bar0_wr_ack                   ),
        .busy           ( bar0_emu_busy                 )
    );

    // 16-deep circular buffer FSM:
    // Push: spill drains first (priority), then new BAR responses.
    // Pop:  when emulator goes idle->busy (bar0_emu_accepted), it took the head data.
    // Push+pop in the same cycle: count stays the same (single NBA expression).
    always @(posedge clk) begin
        if (device_reset) begin
            bar0_buf_count     <= 5'd0;
            bar0_buf_rd        <= 4'd0;
            bar0_buf_wr        <= 4'd0;
            bar0_emu_busy_d1   <= 1'b0;
        end else if (hda_crst_falling) begin
            // CRST soft reset: clear buffer pointers and counters.
            // HDA FSM is resetting, so buffered responses become stale.
            // The buffer will refill with new responses after re-enable.
            // Note: bar0_spill_valid is reset by the spill always block above.
            bar0_buf_count     <= 5'd0;
            bar0_buf_rd        <= 4'd0;
            bar0_buf_wr        <= 4'd0;
            bar0_emu_busy_d1   <= 1'b0;
        end else begin
            bar0_emu_busy_d1 <= bar0_emu_busy;

            // Pop head when emulator accepted (idle->busy transition = took head data)
            if (bar0_buf_pop) begin
                bar0_buf_rd <= bar0_buf_rd + 4'd1;
            end

            // Push tail: bar0_buf_write covers both spill drain and new data.
            // Use the correct data source - spill data gets its own address
            // reconstruction since ctx fields come from a different source.
            if (bar0_buf_write) begin
                if (bar0_spill_valid) begin
                    // Draining spill: use spill's own ctx for address reconstruction
                    bar0_buf_ctx[bar0_buf_wr]  <= bar0_spill_ctx;
                    bar0_buf_data[bar0_buf_wr] <= bar0_spill_data;
                    bar0_buf_addr[bar0_buf_wr] <= {bar0_spill_ctx[31:12], bar0_spill_ctx[11:2], 2'b00};
                end else begin
                    // New response
                    bar0_buf_ctx[bar0_buf_wr]  <= bar0_raw_ctx;
                    bar0_buf_data[bar0_buf_wr] <= bar0_raw_data;
                    bar0_buf_addr[bar0_buf_wr] <= bar0_req_addr_from_ctx;
                end
                bar0_buf_wr <= bar0_buf_wr + 4'd1;
            end

            // single count update: avoids NBA last-write-wins on simultaneous push+pop
            if (bar0_buf_write && !bar0_buf_pop)
                bar0_buf_count <= bar0_buf_count + 5'd1;
            else if (!bar0_buf_write && bar0_buf_pop)
                bar0_buf_count <= bar0_buf_count - 5'd1;
            // else: both or neither -> count unchanged
        end
    end





    wire msix_wr_table_select = wr_valid && wr_bar[0] &&
                                (wr_addr >= 8192) &&
                                (wr_addr < 8272);
    wire msix_wr_pba_select   = wr_valid && wr_bar[0] &&
                                (wr_addr >= 12288) &&
                                (wr_addr < 12296);
    wire msix_rd_table_select = rd_req_valid && rd_req_bar[0] &&
                                (rd_req_addr >= 8192) &&
                                (rd_req_addr < 8272);
    wire msix_rd_pba_select   = rd_req_valid && rd_req_bar[0] &&
                                (rd_req_addr >= 12288) &&
                                (rd_req_addr < 12296);

    pcileech_msix_table #(
        .NUM_VECTORS    ( 5  ),
        .TABLE_BIR      ( 0     ),
        .TABLE_OFFSET   ( 32'h00002000 ),
        .PBA_BIR        ( 0       ),
        .PBA_OFFSET     ( 32'h00003000   )
    ) i_msix_table(
        .rst            ( device_reset                  ),
        .clk            ( clk                           ),
        .wr_addr        ( wr_addr                       ),
        .wr_data        ( wr_data                       ),
        .wr_be          ( wr_be                         ),
        .wr_valid       ( wr_valid                      ),
        .wr_table_select( msix_wr_table_select          ),
        .wr_pba_select  ( msix_wr_pba_select            ),
        .rd_req_ctx     ( rd_req_ctx                    ),
        .rd_req_addr    ( rd_req_addr                   ),
        .rd_req_valid   ( msix_rd_table_select || msix_rd_pba_select ),
        .rd_table_select( msix_rd_table_select          ),
        .rd_pba_select  ( msix_rd_pba_select            ),
        .rd_rsp_ctx     ( msix_rsp_ctx                  ),
        .rd_rsp_data    ( msix_rsp_data                 ),
        .rd_rsp_valid   ( msix_rsp_valid                ),
        .rd_rsp_bir     ( msix_rsp_bir                  ),

        .vector_select  ( nvme_msix_vector_select       ),
        .vector_addr    ( nvme_msix_vector_addr         ),
        .vector_data    ( nvme_msix_vector_data         ),
        .vector_masked  ( nvme_msix_vector_masked       ),
        .pba_set_valid   ( nvme_msix_pba_set_valid       ),
        .pba_set_vector  ( nvme_msix_pba_vector          ),
        .pba_clear_valid ( nvme_msix_pba_clear_valid     ),
        .pba_clear_vector( nvme_msix_pba_vector          ),
        .addr_hit       ( msix_addr_hit                 )
    );





    // NVMe admin responder + DMA bridge

    // Stub HDA TLP signals - unused in NVME-only builds but referenced
    // by the TLP mux below. In HDA+NVME builds, real signals override these.
    wire        hda_tlp_tx_tvalid = 1'b0;
    wire [127:0] hda_tlp_tx_tdata = 128'h0;
    wire [3:0]   hda_tlp_tx_tkeepdw = 4'h0;
    wire         hda_tlp_tx_tlast = 1'b0;
    wire [8:0]   hda_tlp_tx_tuser = 9'h0;


    // doorbell page: index bit[0]=SQ/CQ, remaining bits=QID
    wire [31:0] nvme_db_base  = 32'h00001000;
    wire        nvme_db_wr    = wr_valid && wr_bar[0] && bar0_wr_hit &&
                                (wr_addr_bar0 >= nvme_db_base) &&
                                (wr_addr_bar0 <  nvme_db_base + 32'h00001000);
    wire [31:0] nvme_db_off   = wr_addr_bar0 - nvme_db_base;
    wire [31:0] nvme_db_index = nvme_db_off >> (2 + 0);
    wire        nvme_db_is_cq = nvme_db_index[0];
    wire [15:0] nvme_db_qid   = nvme_db_index[16:1];
    wire [15:0] nvme_db_val   = wr_data[15:0];

    // CC register write -> enable/disable strobes
    wire        nvme_cc_wr         = wr_valid && wr_bar[0] && bar0_wr_hit &&
                                     ((wr_addr_bar0 & 32'hFFFFFFFC) == 32'h00000014);
    wire        nvme_cc_enable_wr  = nvme_cc_wr && wr_data[0];
    wire        nvme_cc_disable_wr = nvme_cc_wr && !wr_data[0];

    // plumbing between the responder and the DMA bridge
    wire        nvme_dma_rd_req;
    wire [63:0] nvme_dma_rd_addr;
    wire [9:0]  nvme_dma_rd_len;
    wire        nvme_dma_rd_valid;
    wire [31:0] nvme_dma_rd_data;
    wire        nvme_dma_rd_done;
    wire        nvme_dma_wr_req;
    wire [63:0] nvme_dma_wr_addr;
    wire [31:0] nvme_dma_wr_data;
    wire [3:0]  nvme_dma_wr_be;
    wire        nvme_dma_wr_valid;
    wire        nvme_dma_wr_done;

    wire [7:0]  nvme_resp_dbg_state;
    wire [15:0] nvme_resp_dbg_qid;
    wire [7:0]  nvme_resp_dbg_opcode;
    (* keep = "true" *) wire [31:0] nvme_resp_dbg_admin_queues;
    (* keep = "true" *) wire [31:0] nvme_resp_dbg_cmd_info;
    wire [7:0]  nvme_disk_dbg_state;
    wire [31:0] nvme_disk_dbg_info;
    (* keep = "true" *) wire [31:0] nvme_dma_dbg_status;
    wire [12:0] nvme_id_rom_addr;
    wire [31:0] nvme_id_rom_data;

    // TLP wires coming out of the DMA bridge
    wire [127:0] nvme_tlp_tx_tdata;
    wire [3:0]   nvme_tlp_tx_tkeepdw;
    wire         nvme_tlp_tx_tvalid;
    wire         nvme_tlp_tx_tlast;
    wire [8:0]   nvme_tlp_tx_tuser;
    wire         nvme_tlp_tx_tready;


    pcileech_interrupt_service #(
        .NUM_VECTORS       ( 5 ),
        .DEFER_MSIX_CLEAR  ( 1 )
    ) i_nvme_interrupt_service(
        .clk               ( clk                           ),
        .rst               ( device_reset                  ),
        .quiesce           ( lifecycle_quiesce             ),
        .msix_mode         ( 1'b1                          ),
        .function_enable   ( cfg_msix_enable               ),
        .function_mask     ( cfg_msix_function_mask        ),
        .event_valid     ( nvme_irq_event_valid          ),
        .event_vector      ( nvme_irq_event_vector         ),
        .vector_select     ( nvme_msix_vector_select       ),
        .vector_masked     ( nvme_msix_vector_masked       ),
        .delivery_ready    ( nvme_irq_delivery_ready       ),
        .delivery_done   ( nvme_irq_delivery_done        ),
        .delivery_valid  ( nvme_irq_delivery_valid       ),
        .delivery_vector ( nvme_irq_delivery_vector      ),
        .msi_pulse         (                               ),
        .pba_set_valid   ( nvme_msix_pba_set_valid       ),
        .pba_clear_valid ( nvme_msix_pba_clear_valid     ),
        .pba_vector        ( nvme_msix_pba_vector          )
    );


    pcileech_nvme_admin_responder #(
        .NVME_ADVERTISED_LBAS    ( NVME_ADVERTISED_LBAS         ),
        .NVME_ENABLE_IO_QUEUES   ( NVME_IO_QUEUES_ENABLED       ),
        .NVME_STUB_IO_DATA       ( NVME_IO_DATA_STUBBED         ),
        .NVME_ZERO_IO_READS      ( NVME_IO_READS_ZEROED         ),
        .NVME_PRP_ONLY_IO        ( NVME_IO_PRP_ONLY             ),
        .NVME_TIMING_ENABLE      ( NVME_TIMING_ENABLED          ),
        .NVME_TIMING_CLK_HZ      ( NVME_TIMING_CLOCK_HZ         )
    ) i_nvme_responder(
        .rst                ( device_reset                  ),
        .clk                ( clk                           ),
        .dma_enabled        ( dma_enabled                   ),
        .cc_en              ( nvme_reg_cc[0]                ),
        .cc_enable_wr       ( nvme_cc_enable_wr             ),
        .cc_disable_wr      ( nvme_cc_disable_wr            ),
        .asq_lo             ( nvme_reg_asq_lo               ),
        .asq_hi             ( nvme_reg_asq_hi               ),
        .acq_lo             ( nvme_reg_acq_lo               ),
        .acq_hi             ( nvme_reg_acq_hi               ),
        .aqa                ( nvme_reg_aqa                  ),
        .doorbell_wr        ( nvme_db_wr                    ),
        .doorbell_is_cq     ( nvme_db_is_cq                 ),
        .doorbell_qid       ( nvme_db_qid                   ),
        .doorbell_val       ( nvme_db_val                   ),
        .msix_vector_addr   ( nvme_msix_vector_addr         ),
        .msix_vector_data   ( nvme_msix_vector_data         ),
        .irq_delivery_valid ( nvme_irq_delivery_valid       ),
        .irq_delivery_ready ( nvme_irq_delivery_ready       ),
        .irq_delivery_done  ( nvme_irq_delivery_done        ),
        .pba_set_valid      ( nvme_irq_event_valid          ),
        .pba_set_vector     ( nvme_irq_event_vector         ),
        .dma_rd_req         ( nvme_dma_rd_req               ),
        .dma_rd_addr        ( nvme_dma_rd_addr              ),
        .dma_rd_len         ( nvme_dma_rd_len               ),
        .dma_rd_valid       ( nvme_dma_rd_valid             ),
        .dma_rd_data        ( nvme_dma_rd_data              ),
        .dma_rd_done        ( nvme_dma_rd_done              ),
        .dma_wr_req         ( nvme_dma_wr_req               ),
        .dma_wr_addr        ( nvme_dma_wr_addr              ),
        .dma_wr_data        ( nvme_dma_wr_data              ),
        .dma_wr_be          ( nvme_dma_wr_be                ),
        .dma_wr_valid       ( nvme_dma_wr_valid             ),
        .dma_wr_done        ( nvme_dma_wr_done              ),
        .disk_req_valid     ( nvme_disk_req_valid           ),
        .disk_req_write     ( nvme_disk_req_write           ),
        .disk_req_flush     ( nvme_disk_req_flush           ),
        .disk_req_lba       ( nvme_disk_req_lba             ),
        .disk_req_word      ( nvme_disk_req_word            ),
        .disk_req_wdata     ( nvme_disk_req_wdata           ),
        .disk_req_done      ( nvme_disk_req_done            ),
        .disk_req_rdata     ( nvme_disk_req_rdata           ),
        .disk_req_hit       ( nvme_disk_req_hit             ),
        .disk_busy          ( nvme_disk_busy                ),
        .disk_error         ( nvme_disk_error               ),
        .id_rom_addr        ( nvme_id_rom_addr              ),
        .id_rom_data        ( nvme_id_rom_data              ),
        .dbg_state          ( nvme_resp_dbg_state           ),
        .dbg_active_qid     ( nvme_resp_dbg_qid             ),
        .dbg_opcode         ( nvme_resp_dbg_opcode          ),
        .dbg_admin_queues   ( nvme_resp_dbg_admin_queues    ),
        .dbg_cmd_info       ( nvme_resp_dbg_cmd_info        )
    );

    assign flash_csn      = 1'b1;
    assign flash_sdi_dq0  = 1'b0;
    assign flash_wpn_dq2  = 1'b1;
    assign flash_hldn_dq3 = 1'b1;

    pcileech_bram_disk #(
        .DISK_WORDS              ( NVME_BRAM_DISK_WORDS )
    ) i_nvme_bram_disk(
        .rst            ( device_reset              ),
        .clk            ( clk                       ),
        .req_valid      ( nvme_disk_req_valid       ),
        .req_write      ( nvme_disk_req_write       ),
        .req_flush      ( nvme_disk_req_flush       ),
        .req_lba        ( nvme_disk_req_lba         ),
        .req_word       ( nvme_disk_req_word        ),
        .req_wdata      ( nvme_disk_req_wdata       ),
        .req_done       ( nvme_disk_req_done        ),
        .req_rdata      ( nvme_disk_req_rdata       ),
        .req_hit        ( nvme_disk_req_hit         ),
        .busy           ( nvme_disk_busy            ),
        .error          ( nvme_disk_error           ),
        .dbg_state      ( nvme_disk_dbg_state       ),
        .dbg_info       ( nvme_disk_dbg_info        )
    );

    pcileech_nvme_dma_bridge i_nvme_dma_bridge(
        .rst                ( device_reset                  ),
        .clk                ( clk                           ),
        .dma_enabled        ( dma_enabled                   ),
        .pcie_id            ( pcie_id                       ),
        .dma_wr_req         ( nvme_dma_wr_req               ),
        .dma_wr_addr        ( nvme_dma_wr_addr              ),
        .dma_wr_data        ( nvme_dma_wr_data              ),
        .dma_wr_be          ( nvme_dma_wr_be                ),
        .dma_wr_valid       ( nvme_dma_wr_valid             ),
        .dma_wr_done        ( nvme_dma_wr_done              ),
        .dma_rd_req         ( nvme_dma_rd_req               ),
        .dma_rd_addr        ( nvme_dma_rd_addr              ),
        .dma_rd_len         ( nvme_dma_rd_len               ),
        .dma_rd_valid       ( nvme_dma_rd_valid             ),
        .dma_rd_data        ( nvme_dma_rd_data              ),
        .dma_rd_done        ( nvme_dma_rd_done              ),
        .tlp_tx_tdata       ( nvme_tlp_tx_tdata             ),
        .tlp_tx_tkeepdw     ( nvme_tlp_tx_tkeepdw           ),
        .tlp_tx_tvalid      ( nvme_tlp_tx_tvalid            ),
        .tlp_tx_tlast       ( nvme_tlp_tx_tlast             ),
        .tlp_tx_tuser       ( nvme_tlp_tx_tuser             ),
        .tlp_tx_tready      ( nvme_tlp_tx_tready            ),
        .tlp_rx_tdata       ( tlps_in.tdata                 ),
        .tlp_rx_tkeepdw     ( tlps_in.tkeepdw               ),
        .tlp_rx_tvalid      ( tlps_in.tvalid                ),
        .tlp_rx_tuser       ( tlps_in.tuser                 ),
        .dbg_status         ( nvme_dma_dbg_status           )
    );

    // 4 KB Identify Controller ROM (1024 words); Namespace is generated at runtime by the responder.
    reg [31:0] nvme_identify_rom [0:1023];
    initial $readmemh("identify_init.hex", nvme_identify_rom);

    reg [31:0] nvme_id_rom_data_r;
    always @(posedge clk)
        nvme_id_rom_data_r <= nvme_identify_rom[nvme_id_rom_addr[11:2]];
    assign nvme_id_rom_data = nvme_id_rom_data_r;

// FIFO buffers DMA bridge TLPs before muxing onto tlps_out.
// DMA TLPs on separate stream (tlps_dma_out); BAR reads on tlps_out.
    wire         nvme_dma_fifo_full;
    wire         nvme_dma_fifo_first;
    wire         nvme_dma_fifo_tlast;
    wire [3:0]   nvme_dma_fifo_tkeepdw;
    wire [127:0] nvme_dma_fifo_tdata;
    wire         nvme_dma_fifo_tvalid;
    reg  [10:0]  nvme_dma_pkt_count;

    wire nvme_dma_fifo_wr_en = nvme_tlp_tx_tvalid && !nvme_dma_fifo_full;
    wire nvme_dma_pkt_inc    = nvme_dma_fifo_wr_en && nvme_tlp_tx_tlast;
    wire nvme_dma_pkt_dec    = nvme_dma_fifo_tvalid && nvme_dma_fifo_tlast;
    wire [10:0] nvme_dma_pkt_count_next = nvme_dma_pkt_count +
                                          {10'h000, nvme_dma_pkt_inc} -
                                          {10'h000, nvme_dma_pkt_dec};
    wire nvme_dma_fifo_rd_en = tlps_dma_out.tready && (nvme_dma_pkt_count_next != 11'd0);

    assign nvme_tlp_tx_tready = !nvme_dma_fifo_full;

    fifo_134_134_clk1_bar_rdrsp i_fifo_nvme_dma(
        .srst       ( device_reset || !dma_enabled                                ),
        .clk        ( clk                                                        ),
        .din        ( { nvme_tlp_tx_tuser[0], nvme_tlp_tx_tlast,
                        nvme_tlp_tx_tkeepdw, nvme_tlp_tx_tdata }                ),
        .wr_en      ( nvme_dma_fifo_wr_en                                        ),
        .rd_en      ( nvme_dma_fifo_rd_en                                        ),
        .dout       ( { nvme_dma_fifo_first, nvme_dma_fifo_tlast,
                        nvme_dma_fifo_tkeepdw, nvme_dma_fifo_tdata }            ),
        .full       ( nvme_dma_fifo_full                                         ),
        .empty      (                                                            ),
        .prog_empty (                                                            ),
        .valid      ( nvme_dma_fifo_tvalid                                       )
    );

    always @(posedge clk) begin
        nvme_dma_pkt_count <= (device_reset || !dma_enabled) ? 11'd0 : nvme_dma_pkt_count_next;
    end

    assign tlps_dma_out.tdata    = nvme_dma_fifo_tdata;
    assign tlps_dma_out.tkeepdw  = nvme_dma_fifo_tkeepdw;
    assign tlps_dma_out.tvalid   = dma_enabled && nvme_dma_fifo_tvalid;
    assign tlps_dma_out.tlast    = nvme_dma_fifo_tlast;
    assign tlps_dma_out.tuser    = {7'h00, nvme_dma_fifo_tlast, nvme_dma_fifo_first};
    assign tlps_dma_out.has_data = dma_enabled && (nvme_dma_pkt_count_next != 11'd0);

    assign tlps_out.tdata    = tlps_cpl.tdata;
    assign tlps_out.tkeepdw  = tlps_cpl.tkeepdw;
    assign tlps_out.tvalid   = tlps_cpl.tvalid;
    assign tlps_out.tlast    = tlps_cpl.tlast;
    assign tlps_out.tuser    = tlps_cpl.tuser;
    assign tlps_out.has_data = tlps_cpl.has_data;
    assign tlps_cpl.tready   = tlps_out.tready;








    pcileech_bar_impl_none i_bar1(
        .rst            ( device_reset                  ),
        .clk            ( clk                           ),
        .wr_addr        ( wr_addr                       ),
        .wr_be          ( wr_be                         ),
        .wr_data        ( wr_data                       ),
        .wr_valid       ( wr_valid && wr_bar[1] ),
        .rd_req_ctx     ( rd_req_ctx                    ),
        .rd_req_addr    ( rd_req_addr                   ),
        .rd_req_valid   ( rd_req_valid && rd_req_bar[1] ),
        .rd_rsp_ctx     ( bar_base_ctx[1]      ),
        .rd_rsp_data    ( bar_base_data[1]     ),
        .rd_rsp_valid   ( bar_base_valid[1]    ),
        .intr_req       (                               )
    );


    pcileech_bar_impl_none i_bar2(
        .rst            ( device_reset                  ),
        .clk            ( clk                           ),
        .wr_addr        ( wr_addr                       ),
